const allTopics = [...rawData, ...additionalTopics, ...moreTopics, ...moreTopicsCont];
const finalOutput = [];

allTopics.forEach(topic => {
  const uniqueTopicWords = [];
  topic.words.forEach(w => {
    const wordText = w[0].toLowerCase();
    if (!existingWords.has(wordText)) {
      uniqueTopicWords.push({
        word: w[0],
        phonetic: w[1],
        partOfSpeech: w[2],
        definition: w[3],
        definitionVi: w[4],
        example: w[5],
        exampleVi: w[6]
      });
      existingWords.add(wordText);
    }
  });
  
  if (uniqueTopicWords.length > 0) {
    finalOutput.push({
      name: topic.name,
      nameVi: topic.nameVi,
      description: topic.description,
      level: topic.level,
      order: topic.order,
      words: uniqueTopicWords
    });
  }
});

fs.writeFileSync('backend/prisma/seed/oxford_3000_batch7.json', JSON.stringify(finalOutput, null, 2));
console.log(`Generated oxford_3000_batch7.json with ${finalOutput.reduce((acc, topic) => acc + topic.words.length, 0)} new unique words across ${finalOutput.length} topics.`);
